// Wait for the DOM to be fully loaded
document.addEventListener('DOMContentLoaded', () => {
  console.log('🚀 My Web Project loaded successfully!');

  // ---- CTA Button ----
  const ctaBtn = document.getElementById('cta-btn');

  const messages = [
    'You clicked the button! 🎉',
    'Nice one! Keep clicking! 💥',
    'You really like this button, huh? 😄',
    'Okay okay, I see you! 🔥',
    'Legend. Absolute legend. 🏆',
  ];

  let clickCount = 0;

  ctaBtn.addEventListener('click', () => {
    clickCount++;
    const msg = messages[(clickCount - 1) % messages.length];
    ctaBtn.textContent = msg;

    // Reset button text after 2 seconds
    setTimeout(() => {
      ctaBtn.textContent = 'Click Me!';
    }, 2000);
  });

  // ---- Card Hover Highlight ----
  const cards = document.querySelectorAll('.card');

  cards.forEach((card) => {
    card.addEventListener('mouseenter', () => {
      card.style.borderColor = '#7f5af0';
    });

    card.addEventListener('mouseleave', () => {
      card.style.borderColor = '#2a2a4e';
    });
  });

  // ---- Dynamic Footer Year ----
  const footer = document.querySelector('footer p');
  if (footer) {
    const year = new Date().getFullYear();
    footer.textContent = `© ${year} My Web Project. All rights reserved.`;
  }
});
