def calculate_factorial(n):
    """Calculate factorial of n recursively."""
    result = 1
    for i in range(1, n + 1):
        result *= i
    return result

def find_primes(limit):
    """Find all prime numbers up to limit."""
    primes = []
    for num in range(2, limit + 1):
        is_prime = True
        for divisor in range(2, int(num ** 0.5) + 1):
            if num % divisor == 0:
                is_prime = False
                break
        if is_prime:
            primes.append(num)
    return primes

def main():
    # Calculate factorials
    numbers = [5, 7, 10]
    for n in numbers:
        fact = calculate_factorial(n)
        print(f"factorial({n}) = {fact}")

    # Find primes
    limit = 30
    primes = find_primes(limit)
    print(f"\nPrimes up to {limit}: {primes}")
    print(f"Total primes found: {len(primes)}")

if __name__ == "__main__":
    main()
EOF

